`call_with_fallback` catches bare `Exception`, so **all six** are handled identically... NON_RETRYABLE = (BadRequestError, ContentPolicyError, AuthError)

def call_with_fallback(payload):
    try:
        return primary.complete(payload)
    except NON_RETRYABLE:
        raise
    except Exception as e:
        log_fallover(e)
        return secondary.complete(payload)
